sp_instance_ais.css:
$sp-space--3xl: 40px !default;
$sp-space--sm: 8px !default;
$text-primary: #272822 !default;
$link-color: #3C59E7 !default;
$brand-primary-opacity: #E3E4F2 !default;
$font-size-h4: 18px !default;
$sp-space--lg: 16px !default;
$sp-space--xxl: 32px !default
$font-size-xl: 24px !default;

#homepage-search {
  padding: $sp-space--3xl $sp-space--xl $sp-space--xl $sp-space--xl !important;
  margin-top: $sp-space--sm;
  display: flex !important;
  flex-direction: column;
  align-items: center;

  h2 {
    font-size: $font-size-xl;
    text-align: center;
    margin-top: 0px;
  }

  h2:empty {
    display: none;
  }

  .wrapper-xl {
    padding: 0px !important;
    width: 100%;
    max-width: 750px;
  }
}

@media (max-width: 991px) and (min-width: 688px) {
  #homepage-search {
    padding: $sp-space--3xl $sp-space--xl $sp-space--lg $sp-space--lg !important;
    margin-top: 0;
    display: flex;
    flex-direction: column;
    align-items: center;
 }
}

@media (max-width: 688px) and (min-width: 481px) {
  #homepage-search {
    padding: $sp-space--3xl $sp-space--sm $sp-space--lg $sp-space--sm !important;
    margin-top: 0px;
    display: flex;
    flex-direction: column;
    align-items: center;

    .wrapper-xl {
      width: 100%;
    }
  }
}


@media (max-width: 480px) {
  #homepage-search {
    padding: $sp-space--xxl $sp-space--sm 0 $sp-space--sm !important;
    margin-top: 0px;
    display: flex;
    flex-direction: column;
    align-items: center;

    .wrapper-xl {
      width: 100%;
    }
  }
}

form {
  height: 46px;
  border-radius: $sp-space--sm;
}

button {
  display: flex;
  align-items: center;
  border: 1px solid $border-tertiary;
  height: 44px !important;
  border-bottom-right-radius: $sp-space--sm;
  border-top-right-radius: $sp-space--sm;
  padding: $sp-space--md $sp-space--xl;
  outline: none;

  &:focus {
    outline: none !important;
    border: 0.1rem solid $link-color;
  }
}

input {
  border: 1px solid $border-tertiary;
  height: 44px;
  font-size: $font-size-base;
  font-family: inherit;
  padding: $sp-space--md $sp-space--xl;

  &:focus {
    outline: none;
    border: 0.1rem solid $link-color;
  }
}

sp_instance_ais.widget_parameters:
{
	"typeahead_search": {
		"value": "{title: 'Search all services, tools or resources for your needs'}",
		"displayValue": "{title: 'Search all services, tools or resources for your needs'}"
	}
}
